	elsif (A='0' and B='0' and C='0' and D='1') then O<="0000000";
	elsif (A='1' and B='0' and C='0' and D='1') then O<="0001100";
	elsif (A='0' and B='1' and C='0' and D='1') then O<="1110010";
	elsif (A='1' and B='1' and C='0' and D='1')then O<="1100110";
	elsif (A='0' and B='0' and C='1' and D='1') then O<="1011100";
	elsif (A='1' and B='0' and C='1' and D='1') then O<="0110100";
	elsif (A='0' and B='1' and C='1' and D='1') then O<="1110000";
	elsif (A='1' and B='1' and C='1' and D='1') then O<="1111111";
   end if;
end process;		
 Y6<=O(6);
 Y5<=O(5);
 Y4<=O(4);
 Y3<=O(3);
 Y2<=O(2);
 Y1<=O(1);
 Y0<=O(0);
end BEHAVIORAL;

