library work;
use work.Stage3_ywl_pkg.ALL;
library IEEE;
use IEEE.STD_LOGIC_1164.ALL;

entity FF_D_CO_NI is
    Port ( D : in  STD_LOGIC;
           CLK : in  STD_LOGIC;
           Q : out  STD_LOGIC;
           Qneg : out  STD_LOGIC);
end FF_D_CO_NI;

architecture BEHAVIORAL of FF_D_CO_NI is

begin
 process (CLK,D)
 begin
  if rising_edge(CLK) then
    if D='1' then Q<='1';
	         Qneg<='0';
	else Q<='0';
	       Qneg<='1';           
    end if;
  end if;
 end process;		
end BEHAVIORAL;

library work;
use work.Stage3_ywl_pkg.ALL;
library IEEE;
use IEEE.STD_LOGIC_1164.ALL;

entity FF_JK_PSCLR_CO_NI is
  port (
   J: in STD_LOGIC;
   K: in STD_LOGIC;
   CLK : in STD_LOGIC;  
   PR: in STD_LOGIC;
   CLR: in STD_LOGIC;
   Q : out STD_LOGIC;
   Qneg : out STD_LOGIC
);
end FF_JK_PSCLR_CO_NI;

architecture BEHAVIORAL of FF_JK_PSCLR_CO_NI is  
signal Qnot: STD_LOGIC:='0';
signal Qpos: STD_LOGIC:='1';

begin
  process (CLK,PR,CLR)
  begin
      if (PR='0' and CLR='1') then  Qpos<='1';
                                                       Qnot<='0';
          elsif (PR='1' and CLR='0') then Qpos<='0';
                                                              Qnot<='1'; 
          elsif (PR='0' and CLR='0') then Qpos<='1';
                                                               Qnot<='1';
          elsif (CLK'event and CLK='1') then
	    if (J='1' and K='1') then Qpos<=Qnot;
		                           Qnot<=Qpos;	
                    elsif (J='0' and K='1') then Qpos<='0';
		                               Qnot<='1';	
	    elsif (J='1' and K='0') then Qpos<='1';
			               Qnot<='0';							  
	    end if;
           end if;
 end process;		
 Qneg<=Qnot;
 Q<=Qpos;
end BEHAVIORAL;

library work;
use work.Stage3_ywl_pkg.ALL;
library IEEE;
use IEEE.STD_LOGIC_1164.ALL;

entity FF_T_CLR_CO_NI is
 port (
    T: in STD_LOGIC;
    CLK : in STD_LOGIC;
    CLR : in STD_LOGIC;
     Q : out STD_LOGIC;
     Qneg : out STD_LOGIC
 );
end FF_T_CLR_CO_NI;

architecture BEHAVIORAL of FF_T_CLR_CO_NI is  
signal Qpos: STD_LOGIC:='1';
signal Qnot: STD_LOGIC:='0';

begin
 process (CLR,T,CLK)
 begin
  if CLR='0' then
	Qpos<='0';
	Qnot<='1';
  elsif (CLK'event and CLK='1') then
     if (T='1') then Qpos<=not Qpos;
	            Qnot<=not Qnot; 
     end if;
  end if;	
 end process;		
 Q<=Qpos;
 Qneg<=Qnot;
end BEHAVIORAL;

library work;
use work.Stage3_ywl_pkg.ALL;
library IEEE;
use IEEE.STD_LOGIC_1164.ALL;

entity MUX4_1_NI is
port (
  Y : out STD_LOGIC;
  I0 : in STD_LOGIC;
  I1 : in STD_LOGIC;
  I2 : in STD_LOGIC;
  I3 : in STD_LOGIC;
  S0 : in STD_LOGIC;
  S1 : in STD_LOGIC;
  EN : in STD_LOGIC
 );
end MUX4_1_NI;

architecture BEHAVIORAL of MUX4_1_NI is  

begin
 process (I0, I1, I2, I3, S0, S1, EN)
 begin
       if EN='1' then Y<='0';
	elsif (S0='0' and S1='0' and I0='0') then Y<='0';
	elsif (S0='0' and S1='0' and I0='1') then Y<='1';
	elsif (S0='1' and S1='0' and I1='0') then Y<='0';
	elsif (S0='1' and S1='0' and I1='1') then Y<='1';
	elsif (S0='0' and S1='1' and I2='0') then Y<='0';
	elsif (S0='0' and S1='1' and I2='1') then Y<='1';
	elsif (S0='1' and S1='1' and I3='0') then Y<='0';
	elsif (S0='1' and S1='1' and I3='1') then Y<='1';
  end if;
 end process;
end BEHAVIORAL;

